              {filtered.map((run) => (
                <Card key={run.url} run={run} idx={runs.indexOf(run)} />
              ))}
            </div>
          </main>
        </>
      )}

      {tab === "prompt" && (
        <main data-screen-label="Prompt">
          <PromptView prompt={prompt} runCount={runs.length} />
        </main>
      )}

      <footer className="site-footer">
        <span>harness-lab · {today}</span>
        <span>Edit data.js to add or remove runs.</span>
      </footer>

      {window.TweaksPanel && (
        <window.TweaksPanel>
          <window.TweakSection label="Layout">
            <window.TweakRadio
              label="Density"
              value={t.density}
              options={[
                { value: "cozy", label: "Cozy" },
                { value: "default", label: "Default" },
                { value: "spacious", label: "Spacious" }
              ]}
              onChange={(v) => setTweak("density", v)}
            />
            <window.TweakSelect
              label="Sort"
              value={t.sort}
              options={[
                { value: "default", label: "As-listed" },
                { value: "model", label: "By model" },
                { value: "harness", label: "By harness" },
                { value: "title", label: "By title" }
              ]}
              onChange={(v) => setTweak("sort", v)}
            />
          </window.TweakSection>
        </window.TweaksPanel>
      )}
    </>
  );
}

